class Solution:
    def countPairs(self, a: list[int]) -> int:
        pairs = 0
        value_count = {}
        for num in a:
            value_count[num] = value_count.get(num, 0) + 1
        for num in set(a):
            if value_count[num] >= 2:
                pairs += value_count[num] * (value_count[num] - 1) // 2
        return pairs

