class Solution {
public:
int countPairs(vector<int>& a) {
    int pairs = 0;
    map<int, int> valueCount;
    for (auto num : a) valueCount[num]++;
    for (auto& pair : valueCount) {
        pairs += pair.second * (pair.second - 1) / 2;
    }
    return pairs;
}
};

